1:/**
2: * The Spider — public types.
3: *
4: * Rig and engine data model, CrawlResult, SpiderApi, and configuration.
5: * Engine yield shapes (DraftYields, SealYields) live here too so downstream
6: * packages can import them without depending on the engine implementation files.
7: */
9:import type { ZodSchema } from 'zod';
11:// ── Engine instance status ────────────────────────────────────────────
13:export type EngineStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled' | 'blocked';
15:// ── Block record ──────────────────────────────────────────────────────
17:/**
18: * Persisted record of an active engine block.
19: * Present on an EngineInstance when status === 'blocked'.
20: * Cleared when the block is resolved.
21: */
22:export interface BlockRecord {
23:  /** Block type identifier (matches a registered BlockType.id). */
24:  type: string;
25:  /** Structured condition payload — shape validated by the block type's conditionSchema. */
26:  condition: unknown;
27:  /** ISO timestamp when the engine was blocked. */
28:  blockedAt: string;
29:  /** Optional human-readable message from the engine. */
30:  message?: string;
31:  /** ISO timestamp of the last checker evaluation. Updated on every check cycle. */
32:  lastCheckedAt?: string;
33:}
35:// ── Engine instance ───────────────────────────────────────────────────
37:/**
38: * A single engine slot within a rig.
39: *
40: * `id` is the engine's position identifier (e.g. 'draft', 'implement').
41: * For the static pipeline it matches `designId`.
42: *
43: * `givensSpec` holds literal values set at spawn time (writ, role, commands).
44: * The Spider assembles `givens` from this directly; upstream yields arrive
45: * via `context.upstream` as the escape hatch.
46: */
47:export interface EngineInstance {
48:  /** Unique identifier within the rig (e.g. 'draft', 'implement'). */
49:  id: string;
50:  /** The engine design to look up in the Fabricator. */
51:  designId: string;
52:  /** Current execution status. */
53:  status: EngineStatus;
54:  /** Engine IDs that must be completed before this engine can run. */
55:  upstream: string[];
56:  /** Literal givens values set at rig spawn time. */
57:  givensSpec: Record<string, unknown>;
58:  /** Yields from a completed engine run (JSON-serializable). */
59:  yields?: unknown;
60:  /** Error message if this engine failed. */
61:  error?: string;
62:  /** Session ID from a launched quick engine, used by the collect step. */
63:  sessionId?: string;
64:  /** ISO timestamp when execution started. */
65:  startedAt?: string;
66:  /** ISO timestamp when execution completed (or failed). */
67:  completedAt?: string;
68:  /** Present when status === 'blocked'. Cleared when the block is resolved. */
69:  block?: BlockRecord;
70:}
72:// ── Rig ──────────────────────────────────────────────────────────────
74:export type RigStatus = 'running' | 'completed' | 'failed' | 'blocked';
76:/**
77: * A rig — the execution context for a single writ.
78: *
79: * Stored in The Stacks (`spider/rigs` book). The `engines` array is the
80: * ordered pipeline of engine instances. The Spider updates this document
81: * in-place as engines run and complete.
82: */
83:export interface RigDoc {
84:  /** Index signature required to satisfy BookEntry constraint. */
85:  [key: string]: unknown;
86:  /** Unique rig id. */
87:  id: string;
88:  /** The writ this rig is executing. */
89:  writId: string;
90:  /** Current rig status. */
91:  status: RigStatus;
92:  /** Ordered engine pipeline. */
93:  engines: EngineInstance[];
94:  /** ISO timestamp when the rig was created. */
95:  createdAt: string;
96:  /** Engine id whose yields provide the resolution summary. Set at spawn time. */
97:  resolutionEngineId?: string;
98:}
100:// ── Rig filters ───────────────────────────────────────────────────────
102:/**
103: * Filters for listing rigs.
104: */
105:export interface RigFilters {
106:  /** Filter by rig status. */
107:  status?: RigStatus;
108:  /** Maximum number of results (default: 20). */
109:  limit?: number;
110:  /** Number of results to skip. */
111:  offset?: number;
112:}
114:// ── Rig templates ─────────────────────────────────────────────────────
116:/**
117: * A single engine slot declared in a rig template.
118: */
119:export interface RigTemplateEngine {
120:  /** Engine id unique within this template. */
121:  id: string;
122:  /** Engine design id to look up in the Fabricator. */
123:  designId: string;
124:  /** Engine ids within this template whose completion is required first. Defaults to []. */
125:  upstream?: string[];
126:  /**
127:   * Givens to pass at spawn time.
128:   * String values starting with '$' are variable references resolved at spawn time.
129:   * Non-string values are passed through literally.
130:   * Variables that resolve to undefined cause the key to be omitted.
131:   */
132:  givens?: Record<string, unknown>;
133:}
135:/**
136: * A complete rig template.
137: */
138:export interface RigTemplate {
139:  /** Ordered list of engine slot declarations. */
140:  engines: RigTemplateEngine[];
141:  /**
142:   * Engine id whose yields provide the writ resolution summary.
143:   * Falls back to seal engine, then last completed engine in array order.
144:   */
145:  resolutionEngine?: string;
146:}
148:// ── CrawlResult ────────────────────────────────────────────────────────
150:/**
151: * The result of a single crawl() call.
152: *
153: * Variants, ordered by priority:
154: * - 'engine-completed'  — an engine finished (collected or ran inline); rig still running
155: * - 'engine-started'    — launched a quick engine's session
156: * - 'engine-blocked'    — engine entered blocked status; rig is still running (other engines active)
157: * - 'engine-unblocked'  — a blocked engine's condition cleared; engine returned to pending
158: * - 'rig-spawned'       — created a new rig for a ready writ
159: * - 'rig-completed'     — the crawl step caused a rig to reach a terminal state
160: * - 'rig-blocked'       — all forward progress stalled; rig entered blocked status
161: *
162: * null means no work was available.
163: */
164:export type CrawlResult =
165:  | { action: 'engine-completed'; rigId: string; engineId: string }
166:  | { action: 'engine-started'; rigId: string; engineId: string }
167:  | { action: 'engine-blocked'; rigId: string; engineId: string; blockType: string }
168:  | { action: 'engine-unblocked'; rigId: string; engineId: string }
169:  | { action: 'rig-spawned'; rigId: string; writId: string }
170:  | { action: 'rig-completed'; rigId: string; writId: string; outcome: 'completed' | 'failed' }
171:  | { action: 'rig-blocked'; rigId: string; writId: string };
173:// ── Block type ────────────────────────────────────────────────────────
175:/**
176: * A registered block type — defines how to check whether a blocking
177: * condition has cleared. Contributed via kit/supportKit `blockTypes`.
178: */
179:export interface BlockType {
180:  /** Unique identifier (e.g. 'writ-status', 'scheduled-time'). */
181:  id: string;
182:  /** Lightweight checker — returns true if the blocking condition has cleared. */
183:  check: (condition: unknown) => Promise<boolean>;
184:  /** Zod schema for validating the condition payload at block time. */
185:  conditionSchema: ZodSchema;
186:  /** Suggested poll interval in milliseconds. If absent, check every crawl cycle. */
187:  pollIntervalMs?: number;
188:}
190:// ── SpiderApi ─────────────────────────────────────────────────────────
192:/**
193: * The Spider's public API — retrieved via guild().apparatus<SpiderApi>('spider').
194: */
195:export interface SpiderApi {
196:  /**
197:   * Execute one step of the crawl loop.
198:   *
199:   * Priority ordering: collect > checkBlocked > run > spawn.
200:   * Returns null when no work is available.
201:   */
202:  crawl(): Promise<CrawlResult | null>;
204:  /**
205:   * Show a rig by id. Throws if not found.
206:   */
207:  show(id: string): Promise<RigDoc>;
209:  /**
210:   * List rigs with optional filters, ordered by createdAt descending.
211:   */
212:  list(filters?: RigFilters): Promise<RigDoc[]>;
214:  /**
215:   * Find the rig for a given writ. Returns null if no rig exists.
216:   */
217:  forWrit(writId: string): Promise<RigDoc | null>;
219:  /**
220:   * Manually clear a block on a specific engine, regardless of checker result.
221:   * Throws if the engine is not blocked.
222:   */
223:  resume(rigId: string, engineId: string): Promise<void>;
225:  /**
226:   * Look up a registered block type by ID.
227:   */
228:  getBlockType(id: string): BlockType | undefined;
229:}
231:// ── Configuration ─────────────────────────────────────────────────────
233:/**
234: * Spider apparatus configuration — lives under the `spider` key in guild.json.
235: */
236:export interface SpiderConfig {
237:  /**
238:   * Role to summon for quick engine sessions.
239:   * Default: 'artificer'.
240:   */
241:  role?: string;
242:  /**
243:   * Polling interval for crawlContinual tool (milliseconds).
244:   * Default: 5000.
245:   */
246:  pollIntervalMs?: number;
247:  /**
248:   * Build command to pass to quick engines.
249:   */
250:  buildCommand?: string;
251:  /**
252:   * Test command to pass to quick engines.
253:   */
254:  testCommand?: string;
255:  /**
256:   * Writ type → rig template mappings.
257:   * 'default' key is the fallback for unmatched writ types.
258:   * Spawning fails if no matching template is found.
259:   */
260:  rigTemplates?: Record<string, RigTemplate>;
261:}
263:// ── Engine yield shapes ───────────────────────────────────────────────
265:/**
266: * Yields from the `draft` clockwork engine.
267: * The Spider stores these in the engine instance and passes them
268: * to downstream engines via context.upstream['draft'].
269: */
270:export interface DraftYields {
271:  /** The draft's unique id. */
272:  draftId: string;
273:  /** Codex this draft belongs to. */
274:  codexName: string;
275:  /** Git branch name for the draft. */
276:  branch: string;
277:  /** Absolute filesystem path to the draft's worktree. */
278:  path: string;
279:  /** HEAD commit SHA at the time the draft was opened. Used by review engine to compute diffs. */
280:  baseSha: string;

