1:/**
2: * The Spider — rig execution engine apparatus.
3: *
4: * The Spider drives writ-to-completion by managing rigs: ordered pipelines
5: * of engine instances. Each crawl() call performs one unit of work:
6: *
7: *   collect > checkBlocked > run > spawn   (priority order)
8: *
9: * collect      — check running engines for terminal session results
10: * checkBlocked — poll registered block type checkers; unblock engines when cleared
11: * run          — execute the next pending engine (clockwork inline, quick → launch)
12: * spawn        — create a new rig for a ready writ with no existing rig
13: *
14: * CDC on the rigs book (Phase 1 cascade) transitions the associated writ
15: * when a rig reaches a terminal state (completed or failed).
16: * The blocked status does NOT trigger the CDC handler.
17: *
18: * See: docs/architecture/apparatus/spider.md
19: */
21:import type { Plugin, StartupContext, LoadedPlugin } from '@shardworks/nexus-core';
22:import { guild, generateId, isLoadedKit, isLoadedApparatus } from '@shardworks/nexus-core';
23:import type { StacksApi, Book, ReadOnlyBook, WhereClause } from '@shardworks/stacks-apparatus';
24:import type { ClerkApi, WritDoc } from '@shardworks/clerk-apparatus';
25:import type { FabricatorApi } from '@shardworks/fabricator-apparatus';
26:import type { SessionDoc } from '@shardworks/animator-apparatus';
28:import type {
29:  RigDoc,
30:  RigFilters,
31:  EngineInstance,
32:  SpiderApi,
33:  CrawlResult,
34:  SpiderConfig,
35:  BlockRecord,
36:  BlockType,
37:  RigTemplate,
38:} from './types.ts';
40:import {
41:  draftEngine,
42:  implementEngine,
43:  reviewEngine,
44:  reviseEngine,
45:  sealEngine,
46:} from './engines/index.ts';
48:import {
49:  writStatusBlockType,
50:  scheduledTimeBlockType,
51:  bookUpdatedBlockType,
52:} from './block-types/index.ts';
54:import {
55:  crawlOneTool,
56:  crawlContinualTool,
57:  rigShowTool,
58:  rigListTool,
59:  rigForWritTool,
60:  rigResumeTool,
61:} from './tools/index.ts';
63:// ── Helpers ────────────────────────────────────────────────────────────
65:/**
66: * Check whether a value is JSON-serializable.
67: * Non-serializable yields cause engine failure — the Stacks cannot store them.
68: */
69:function isJsonSerializable(value: unknown): boolean {
70:  try {
71:    JSON.stringify(value);
72:    return true;
73:  } catch {
74:    return false;
75:  }
76:}
78:/**
79: * Build the upstream yields map for a rig: all completed engine yields
80: * keyed by engine id. Passed as context.upstream to the engine's run().
81: */
82:function buildUpstreamMap(rig: RigDoc): Record<string, unknown> {
83:  const upstream: Record<string, unknown> = {};
84:  for (const engine of rig.engines) {
85:    if (engine.status === 'completed' && engine.yields !== undefined) {
86:      upstream[engine.id] = engine.yields;
87:    }
88:  }
89:  return upstream;
90:}
92:/**
93: * Find the first pending engine whose entire upstream is completed.
94: * Returns null if no runnable engine exists.
95: */
96:function findRunnableEngine(rig: RigDoc): EngineInstance | null {
97:  for (const engine of rig.engines) {
98:    if (engine.status !== 'pending') continue;
99:    const allUpstreamDone = engine.upstream.every((upstreamId) => {
100:      const dep = rig.engines.find((e) => e.id === upstreamId);
101:      return dep?.status === 'completed';
102:    });
103:    if (allUpstreamDone) return engine;
104:  }
105:  return null;
106:}
108:/**
109: * Determine whether a rig should enter the blocked state.
110: *
111: * A rig is blocked when:
112: * - No engine is currently running
113: * - No engine is runnable (pending with all upstream completed)
114: * - At least one engine is blocked
115: */
116:function isRigBlocked(engines: EngineInstance[]): boolean {
117:  const hasRunning = engines.some((e) => e.status === 'running');
118:  if (hasRunning) return false;
119:  const hasBlocked = engines.some((e) => e.status === 'blocked');
120:  if (!hasBlocked) return false;
121:  // Check runnability by constructing a minimal RigDoc-like object
122:  const syntheticRig = { engines } as RigDoc;
123:  return findRunnableEngine(syntheticRig) === null;
124:}
126:/**
127: * Produce the five-engine static pipeline for a writ.
128: * Each engine receives only the givens it needs.
129: * Upstream yields arrive via context.upstream at run time.
130: */
131:function buildStaticEngines(writ: WritDoc, config: SpiderConfig): EngineInstance[] {
132:  const role = config.role ?? 'artificer';
